import{_ as i,o as a,c as t,aA as o}from"./chunks/framework.CPxl66na.js";const m=JSON.parse('{"title":"Accounting model and event loop","description":"","frontmatter":{},"headers":[],"relativePath":"concepts.md","filePath":"concepts.md","lastUpdated":null}'),n={name:"concepts.md"};function l(r,e,s,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="Accounting-model-and-event-loop" tabindex="-1">Accounting model and event loop <a class="header-anchor" href="#Accounting-model-and-event-loop" aria-label="Permalink to &quot;Accounting model and event loop {#Accounting-model-and-event-loop}&quot;">​</a></h1><p>Fastback is an event-driven accounting engine. You feed it events (marks, FX, funding, expiries), and it updates balances, equity, and margin deterministically.</p><h2 id="Core-objects-quick-definitions" tabindex="-1">Core objects (quick definitions) <a class="header-anchor" href="#Core-objects-quick-definitions" aria-label="Permalink to &quot;Core objects (quick definitions) {#Core-objects-quick-definitions}&quot;">​</a></h2><ul><li><p>Account: the central ledger (cash, positions, trades, equity, margin, cashflows).</p></li><li><p>Cash: a funding currency (USD, EUR, BTC) with balances and equity tracked per symbol.</p></li><li><p>InstrumentSpec: immutable contract metadata (symbols, settlement, margin, lifecycle).</p></li><li><p>Instrument: account-bound handle with instrument/cash indices resolved at registration.</p></li><li><p>Order: intent to trade at a given time, price, quantity.</p></li><li><p>Trade: realized fill produced by <code>fill_order!</code>.</p></li><li><p>Position: netted exposure per instrument with average entry price.</p></li></ul><h2 id="Balances-vs-equity" tabindex="-1">Balances vs equity <a class="header-anchor" href="#Balances-vs-equity" aria-label="Permalink to &quot;Balances vs equity {#Balances-vs-equity}&quot;">​</a></h2><ul><li><p>Balance is cash-only. Deposits, withdrawals, commissions, and realized P&amp;L change balances.</p></li><li><p>Equity is balance plus unrealized P&amp;L for open positions in that currency.</p></li><li><p><code>update_marks!</code> recalculates unrealized P&amp;L and updates equity.</p></li><li><p>For variation-margin instruments, unrealized P&amp;L is settled into cash on each mark, so balances move as well.</p></li><li><p>Principal-exchange spot shorts increase cash balance by short-sale proceeds. Interest accrual can exclude those proceeds from the regular lend base and optionally apply a separate short-proceeds rebate rate via broker configuration.</p></li></ul><h2 id="Realized-vs-unrealized-P-and-L" tabindex="-1">Realized vs unrealized P&amp;L <a class="header-anchor" href="#Realized-vs-unrealized-P-and-L" aria-label="Permalink to &quot;Realized vs unrealized P&amp;amp;L {#Realized-vs-unrealized-P-and-L}&quot;">​</a></h2><ul><li><p>Fill-level additive gross P&amp;L is recorded on <code>Trade</code> as <code>fill_pnl_settle</code>.</p></li><li><p>Net fill cash movement is <code>cash_delta_settle</code>.</p></li><li><p>Unrealized P&amp;L lives on the <code>Position</code> (<code>pnl_quote</code>, <code>pnl_settle</code>) and is mirrored into equity via <code>update_marks!</code> or <code>process_step!</code>.</p></li></ul><h2 id="Settlement-styles" tabindex="-1">Settlement styles <a class="header-anchor" href="#Settlement-styles" aria-label="Permalink to &quot;Settlement styles {#Settlement-styles}&quot;">​</a></h2><ul><li><p>PrincipalExchange: fills exchange principal; open position value is marked notional (<code>qty * price * multiplier</code>).</p></li><li><p>VariationMargin: mark-to-market P&amp;L is settled into cash at each mark; open position value stays at zero.</p></li></ul><p><code>AccountFunding.FullyFunded</code> is a funding policy, not a settlement style.</p><h2 id="Margin-requirements-and-styles" tabindex="-1">Margin requirements and styles <a class="header-anchor" href="#Margin-requirements-and-styles" aria-label="Permalink to &quot;Margin requirements and styles {#Margin-requirements-and-styles}&quot;">​</a></h2><ul><li><p>Funding policies: <code>AccountFunding.FullyFunded</code> enforces fully funded exposure (full notional margin), disallows short exposure, prices requirements from liquidation marks (bid for longs, ask for shorts), and requires withdrawals to respect available funds; <code>AccountFunding.Margined</code> uses instrument margin settings, with margin priced from marks for <code>VariationMargin</code> instruments and from last-trade for other settlement styles.</p></li><li><p>Margin requirements on instruments: <code>PercentNotional</code>, <code>FixedPerContract</code>.</p></li><li><p><code>PercentNotional</code> uses IMR/MMR-style equity fractions of notional: <code>required_margin = rate * abs(qty) * abs(price) * multiplier</code>.</p></li><li><p>For short rules expressed as total collateral (for example &quot;150% of short notional&quot;), convert to equity fraction before configuring Fastback: <code>150% -&gt; 0.50</code>.</p></li><li><p>Margin aggregation: <code>PerCurrency</code> or <code>BaseCurrency</code>, controlling how margin totals are aggregated.</p></li></ul><h2 id="Event-loop" tabindex="-1">Event loop <a class="header-anchor" href="#Event-loop" aria-label="Permalink to &quot;Event loop {#Event-loop}&quot;">​</a></h2><p>The engine is driven by explicit events.</p><p>A typical loop is:</p><ol><li><p>Advance time (enforced non-decreasing timestamps): <code>advance_time!</code>.</p></li><li><p>Accrue interest and borrow fees as needed: <code>accrue_interest!</code>, <code>accrue_borrow_fees!</code>.</p></li><li><p>Apply FX updates if you run multi-currency: <code>update_rate!</code> (or <code>process_step!</code> with <code>FXUpdate</code>).</p></li><li><p>Mark positions with bid/ask/last prices: <code>update_marks!</code>.</p></li><li><p>Apply funding events (perpetuals): <code>apply_funding!</code>.</p></li><li><p>Process expiries (futures): <code>process_expiries!</code>.</p></li><li><p>Optionally liquidate to maintenance: <code>liquidate_to_maintenance!</code>.</p></li><li><p>Decide and fill new orders for that step: <code>fill_order!</code> (after <code>Order</code> creation).</p></li></ol><p>You can either:</p><ul><li><p>Use <code>process_step!</code> to run steps 1-7 in one call (recommended for clean, deterministic loops).</p></li><li><p>Call the individual functions manually when you need custom ordering.</p></li></ul><p>The <a href="./how_to">How-to</a> page shows both styles with code snippets.</p>',20)])])}const h=i(n,[["render",l]]);export{m as __pageData,h as default};
